# TDD green phase: minimum implementation to pass all Pester tests.
# Supports JUnit XML and JSON result formats; identifies flaky tests;
# outputs a GitHub Actions-compatible markdown summary.

Set-StrictMode -Version Latest

function ConvertFrom-JUnitXml {
    <#
    .SYNOPSIS  Parse a JUnit XML file and return a run result object.
    #>
    param(
        [Parameter(Mandatory)][string]$Path
    )

    $xml      = [xml](Get-Content -Path $Path -Raw -ErrorAction Stop)
    $runName  = [System.IO.Path]::GetFileNameWithoutExtension($Path)
    $tests    = [System.Collections.Generic.List[PSCustomObject]]::new()
    $duration = 0.0

    foreach ($suite in @($xml.testsuites.testsuite)) {
        $duration += [double]$suite.time

        foreach ($tc in @($suite.testcase)) {
            $status  = 'passed'
            $message = $null

            if ($tc.failure) {
                $status  = 'failed'
                $message = $tc.failure.message
            } elseif ($tc.skipped) {
                $status = 'skipped'
            }

            $tests.Add([PSCustomObject]@{
                Name     = $tc.name
                Suite    = $tc.classname
                Status   = $status
                Duration = [double]$tc.time
                Message  = $message
                Run      = $runName
                File     = $Path
            })
        }
    }

    [PSCustomObject]@{
        Run      = $runName
        Duration = $duration
        Tests    = $tests.ToArray()
    }
}

function ConvertFrom-JsonResults {
    <#
    .SYNOPSIS  Parse a JSON test-results file and return a run result object.
    #>
    param(
        [Parameter(Mandatory)][string]$Path
    )

    $data    = Get-Content -Path $Path -Raw -ErrorAction Stop | ConvertFrom-Json
    $runName = if ($data.run) { $data.run } else {
        [System.IO.Path]::GetFileNameWithoutExtension($Path)
    }
    $tests   = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($t in $data.tests) {
        $tests.Add([PSCustomObject]@{
            Name     = $t.name
            Suite    = $t.suite
            Status   = $t.status
            Duration = [double]$t.duration
            Message  = if ($t.PSObject.Properties['message']) { $t.message } else { $null }
            Run      = $runName
            File     = $Path
        })
    }

    [PSCustomObject]@{
        Run      = $runName
        Duration = [double]$data.duration
        Tests    = $tests.ToArray()
    }
}

function Merge-TestResults {
    <#
    .SYNOPSIS  Aggregate an array of run-result objects into cumulative totals.
    #>
    param(
        [Parameter(Mandatory)][array]$RunResults
    )

    $all      = [System.Collections.Generic.List[PSCustomObject]]::new()
    $passed   = 0
    $failed   = 0
    $skipped  = 0
    $duration = 0.0

    foreach ($run in $RunResults) {
        $duration += $run.Duration
        foreach ($t in $run.Tests) {
            $all.Add($t)
            switch ($t.Status) {
                'passed'  { $passed++  }
                'failed'  { $failed++  }
                'skipped' { $skipped++ }
            }
        }
    }

    [PSCustomObject]@{
        TotalPassed   = $passed
        TotalFailed   = $failed
        TotalSkipped  = $skipped
        TotalDuration = [Math]::Round($duration, 1)
        Tests         = $all.ToArray()
    }
}

function Find-FlakyTests {
    <#
    .SYNOPSIS  Return names of tests that both passed and failed across runs.
               Skipped results are neutral and never trigger flaky classification.
    #>
    param(
        [Parameter(Mandatory)][array]$AllTests
    )

    $grouped = $AllTests | Group-Object -Property Name
    $flaky   = [System.Collections.Generic.List[string]]::new()

    foreach ($grp in $grouped) {
        $statuses   = $grp.Group.Status | Where-Object { $_ -ne 'skipped' }
        $hasPassed  = $statuses -contains 'passed'
        $hasFailed  = $statuses -contains 'failed'

        if ($hasPassed -and $hasFailed) {
            $flaky.Add($grp.Name)
        }
    }

    # Return sorted so output is deterministic
    $flaky | Sort-Object
}

function New-MarkdownSummary {
    <#
    .SYNOPSIS  Build a GitHub Actions job-summary markdown string.
    #>
    param(
        [Parameter(Mandatory)][PSCustomObject]$Aggregated,
        [Parameter(Mandatory)][AllowEmptyCollection()][array]$FlakyTests
    )

    $total    = $Aggregated.TotalPassed + $Aggregated.TotalFailed + $Aggregated.TotalSkipped
    $passRate = if ($total -gt 0) {
        [Math]::Round(($Aggregated.TotalPassed / $total) * 100, 1)
    } else { 0 }

    $sb = [System.Text.StringBuilder]::new()
    $null = $sb.AppendLine("## Test Results Summary")
    $null = $sb.AppendLine("")
    $null = $sb.AppendLine("| Metric | Value |")
    $null = $sb.AppendLine("|--------|-------|")
    $null = $sb.AppendLine("| Total Tests | $total |")
    $null = $sb.AppendLine("| Passed | $($Aggregated.TotalPassed) |")
    $null = $sb.AppendLine("| Failed | $($Aggregated.TotalFailed) |")
    $null = $sb.AppendLine("| Skipped | $($Aggregated.TotalSkipped) |")
    $null = $sb.AppendLine("| Pass Rate | $passRate% |")
    $null = $sb.AppendLine("| Total Duration | $($Aggregated.TotalDuration)s |")
    $null = $sb.AppendLine("")

    if ($FlakyTests.Count -gt 0) {
        $null = $sb.AppendLine("### Flaky Tests ($($FlakyTests.Count))")
        $null = $sb.AppendLine("")
        $null = $sb.AppendLine("The following tests had inconsistent results across runs:")
        $null = $sb.AppendLine("")
        foreach ($t in $FlakyTests) {
            $null = $sb.AppendLine("- $t")
        }
        $null = $sb.AppendLine("")
    } else {
        $null = $sb.AppendLine("### No Flaky Tests Detected")
        $null = $sb.AppendLine("")
    }

    $sb.ToString()
}

function Invoke-TestAggregator {
    <#
    .SYNOPSIS  Parse, aggregate, and summarise test results from multiple files.
    .PARAMETER InputPaths  One or more .xml (JUnit) or .json result files.
    .PARAMETER OutputPath  Optional path to write the markdown summary file.
    #>
    param(
        [Parameter(Mandatory)][string[]]$InputPaths,
        [string]$OutputPath
    )

    $runResults = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($path in $InputPaths) {
        if (-not (Test-Path $path)) {
            Write-Error "File not found: $path"
            continue
        }

        $ext = [System.IO.Path]::GetExtension($path).ToLower()
        try {
            switch ($ext) {
                '.xml'  { $runResults.Add((ConvertFrom-JUnitXml    -Path $path)) }
                '.json' { $runResults.Add((ConvertFrom-JsonResults  -Path $path)) }
                default { Write-Warning "Unsupported format '$ext' — skipping: $path" }
            }
        } catch {
            Write-Error "Failed to parse '$path': $_"
        }
    }

    if ($runResults.Count -eq 0) {
        Write-Error "No valid test result files could be parsed."
        return
    }

    $aggregated  = Merge-TestResults  -RunResults $runResults.ToArray()
    $flakyTests  = Find-FlakyTests    -AllTests   $aggregated.Tests
    $markdown    = New-MarkdownSummary -Aggregated $aggregated -FlakyTests $flakyTests

    # Emit structured markers so the CI harness can assert exact values.
    Write-Host "AGGREGATED_PASSED=$($aggregated.TotalPassed)"
    Write-Host "AGGREGATED_FAILED=$($aggregated.TotalFailed)"
    Write-Host "AGGREGATED_SKIPPED=$($aggregated.TotalSkipped)"
    Write-Host "AGGREGATED_DURATION=$($aggregated.TotalDuration)"
    Write-Host "FLAKY_COUNT=$($flakyTests.Count)"
    if ($flakyTests.Count -gt 0) {
        Write-Host "FLAKY_TESTS=$($flakyTests -join ',')"
    }
    Write-Host ""
    Write-Host $markdown

    if ($OutputPath) {
        $markdown | Out-File -FilePath $OutputPath -Encoding UTF8 -NoNewline:$false
        Write-Host "Markdown written to: $OutputPath"
    }

    # Append to GitHub Actions step summary when the env var is available.
    if ($env:GITHUB_STEP_SUMMARY) {
        $markdown | Out-File -FilePath $env:GITHUB_STEP_SUMMARY -Encoding UTF8 -Append
    }

    [PSCustomObject]@{
        Aggregated = $aggregated
        FlakyTests = $flakyTests
        Markdown   = $markdown
    }
}

# Test harness: runs the GitHub Actions workflow via act and validates output.
# All testing goes through the act pipeline — this script does NOT call the
# aggregator script directly.
#
# Expected exact values from the 4 fixture files:
#   TotalPassed   = 23   (6+6+5+6)
#   TotalFailed   = 5    (1+2+1+1)
#   TotalSkipped  = 2    (1+0+1+0)
#   TotalDuration = 40.1 (12.5+10.2+8.3+9.1)
#   FlakyCount    = 4    (TestAPICall, TestDivide, TestLogout, TestSubtract)

Set-StrictMode -Version Latest
$ErrorActionPreference = 'Stop'

$ResultFile = Join-Path $PSScriptRoot 'act-result.txt'
$Passed     = 0
$Failed     = 0

function Write-Pass { param([string]$Msg) Write-Host "  PASS: $Msg" -ForegroundColor Green; $script:Passed++ }
function Write-Fail { param([string]$Msg) Write-Host "  FAIL: $Msg" -ForegroundColor Red;   $script:Failed++ }

function Assert-Match {
    param([string]$Text, [string]$Pattern, [string]$Description)
    if ($Text -match [regex]::Escape($Pattern)) {
        Write-Pass $Description
    } else {
        # Try as-is (Pattern may already be a regex)
        if ($Text -match $Pattern) {
            Write-Pass $Description
        } else {
            Write-Fail "$Description (pattern: '$Pattern' not found)"
        }
    }
}

function Assert-Regex {
    param([string]$Text, [string]$Pattern, [string]$Description)
    if ($Text -match $Pattern) {
        Write-Pass $Description
    } else {
        Write-Fail "$Description (regex '$Pattern' not found)"
    }
}

# ─── Test Group 1: Static checks (actionlint, file paths) ────────────────────

Write-Host "`n=== Static Checks ===" -ForegroundColor Cyan

$wfPath = Join-Path $PSScriptRoot '.github/workflows/test-results-aggregator.yml'

if (Test-Path $wfPath) {
    Write-Pass "Workflow file exists at .github/workflows/test-results-aggregator.yml"
} else {
    Write-Fail "Workflow file missing at $wfPath"
}

if (Test-Path (Join-Path $PSScriptRoot 'src/Invoke-TestAggregator.ps1')) {
    Write-Pass "Source script exists at src/Invoke-TestAggregator.ps1"
} else {
    Write-Fail "Source script missing"
}

# Verify workflow YAML structure
$wfContent = Get-Content $wfPath -Raw
Assert-Regex $wfContent 'push:'             "Workflow has push trigger"
Assert-Regex $wfContent 'pull_request:'     "Workflow has pull_request trigger"
Assert-Regex $wfContent 'workflow_dispatch:' "Workflow has workflow_dispatch trigger"
Assert-Regex $wfContent 'shell:\s*pwsh'     "Workflow uses shell: pwsh"
Assert-Regex $wfContent 'Invoke-TestAggregator\.ps1' "Workflow references the aggregator script"
Assert-Regex $wfContent 'actions/checkout@v4' "Workflow uses actions/checkout@v4"

# Run actionlint and assert exit 0
Write-Host "`n  Running actionlint..." -ForegroundColor Gray
$alOutput = & actionlint $wfPath 2>&1
if ($LASTEXITCODE -eq 0) {
    Write-Pass "actionlint exits 0 (no errors)"
} else {
    Write-Fail "actionlint found errors: $alOutput"
}

# ─── Test Group 2: act run ────────────────────────────────────────────────────

Write-Host "`n=== Act Pipeline Run ===" -ForegroundColor Cyan
Write-Host "  Running: act push --rm  (this may take 30-90s)" -ForegroundColor Gray

# Delimiter so multiple test case outputs are clearly separated in the file.
$delimiter = "=" * 72
$header    = @"
$delimiter
TEST CASE: Full fixture run  ($(Get-Date -Format 'yyyy-MM-dd HH:mm:ss'))
$delimiter
"@

Add-Content -Path $ResultFile -Value $header

$actOutput = & act push --rm 2>&1
$actExitCode = $LASTEXITCODE
$actText   = $actOutput -join "`n"

Add-Content -Path $ResultFile -Value $actText
Add-Content -Path $ResultFile -Value ""

# Assert act exit code
if ($actExitCode -eq 0) {
    Write-Pass "act exited with code 0"
} else {
    Write-Fail "act exited with code $actExitCode"
    Write-Host "  Last 40 lines of act output:" -ForegroundColor Yellow
    $actOutput | Select-Object -Last 40 | ForEach-Object { Write-Host "    $_" }
}

# Assert "Job succeeded"
if ($actText -match 'Job succeeded') {
    Write-Pass "Job succeeded message present"
} else {
    Write-Fail "Job succeeded message NOT found in act output"
}

# Assert exact aggregated values in act output
Assert-Regex $actText 'AGGREGATED_PASSED=23'   "Exact: TotalPassed = 23"
Assert-Regex $actText 'AGGREGATED_FAILED=5'    "Exact: TotalFailed = 5"
Assert-Regex $actText 'AGGREGATED_SKIPPED=2'   "Exact: TotalSkipped = 2"
Assert-Regex $actText 'AGGREGATED_DURATION=40\.1' "Exact: TotalDuration = 40.1"
Assert-Regex $actText 'FLAKY_COUNT=4'          "Exact: FlakyCount = 4"
Assert-Regex $actText 'FLAKY_TESTS=TestAPICall,TestDivide,TestLogout,TestSubtract' "Exact: sorted flaky test names"

# Assert Pester results visible in output
Assert-Regex $actText 'Tests Passed:\s+\d+'    "Pester passed-count line present"
Assert-Regex $actText 'Tests Failed:\s+0'      "Pester reports 0 failures"

# ─── Summary ──────────────────────────────────────────────────────────────────

Write-Host ""
Write-Host ("=" * 60) -ForegroundColor Cyan
$total = $Passed + $Failed
Write-Host "Results: $Passed/$total assertions passed" -ForegroundColor $(if ($Failed -eq 0) { 'Green' } else { 'Red' })
Write-Host "act-result.txt written to: $ResultFile" -ForegroundColor Gray

if ($Failed -gt 0) {
    Write-Host "HARNESS FAILED: $Failed assertion(s) did not pass." -ForegroundColor Red
    exit 1
} else {
    Write-Host "HARNESS PASSED: all assertions satisfied." -ForegroundColor Green
    exit 0
}
